#version 300 es
// Pixel Snapper (native GLSL) — stage 1/3: k-means color quantization.
//
// Node setup: core GLSLShader, size_mode = from_input.
//   image0 = source image (becomes the ping-pong buffer after pass 0)
//   image1 = the SAME source image again (stable copy for the final pass)
//   u_int0 = color_count K (2..32, 0 -> 16)
// Outputs:
//   IMAGE0 = quantized image (every pixel snapped to its nearest centroid)
//   IMAGE1 = palette stripes (K vertical bands; stage 3 samples these)
//
// Working state lives in the ping-pong buffer: row 0 cols 0..K-1 hold the
// centroids, rows 1..GRID hold a GRID x GRID downsample of the source used
// for the k-means iterations.
#pragma passes 13

precision highp float;

const int MAX_K = 32;
const int GRID = 64;        // cached source samples per axis
const int NUM_PASSES = 13;  // keep equal to `#pragma passes` above

uniform sampler2D u_image0; // pass 0: source; pass 1+: ping-pong buffer
uniform sampler2D u_image1; // source (stable across passes)
uniform vec2 u_resolution;
uniform int u_int0;         // color_count K
uniform int u_pass;

in vec2 v_texCoord;
layout(location = 0) out vec4 fragColor0;
layout(location = 1) out vec4 fragColor1;

int kColors() { return clamp(u_int0 <= 0 ? 16 : u_int0, 2, MAX_K); }

vec3 readCentroid(int i) { return texelFetch(u_image0, ivec2(i, 0), 0).rgb; }
vec3 readCache(int sx, int sy) { return texelFetch(u_image0, ivec2(sx, sy + 1), 0).rgb; }

int nearestCentroid(vec3 p, int k) {
    float best = 1e9;
    int bi = 0;
    for (int j = 0; j < MAX_K; j++) {
        if (j >= k) break;
        vec3 d = p - readCentroid(j);
        float dist = dot(d, d);
        if (dist < best) { best = dist; bi = j; }
    }
    return bi;
}

void main() {
    int k = kColors();
    ivec2 frag = ivec2(gl_FragCoord.xy);

    // PASS 0: cache a GRID x GRID downsample of the source (rows 1..GRID).
    if (u_pass == 0) {
        if (frag.y >= 1 && frag.y <= GRID && frag.x < GRID) {
            vec2 uv = (vec2(float(frag.x), float(frag.y - 1)) + 0.5) / float(GRID);
            fragColor0 = vec4(texture(u_image0, uv).rgb, 1.0);
        } else {
            fragColor0 = vec4(0.0, 0.0, 0.0, 1.0);
        }
        fragColor1 = vec4(0.0, 0.0, 0.0, 1.0);
        return;
    }

    // PASS 1: farthest-point seeding. Fragment (j, 0) replays the greedy
    // maximin sequence over the cached samples and writes centroid j.
    // Deterministic, and unlike random scatter it will not start two
    // centroids inside the same dominant color.
    if (u_pass == 1) {
        if (frag.y == 0 && frag.x < k) {
            vec3 chosen[MAX_K];
            chosen[0] = readCache(0, 0);
            for (int s = 1; s < MAX_K; s++) {
                if (s > frag.x) break;
                float bestD = -1.0;
                vec3 bestP = chosen[0];
                for (int sy = 0; sy < GRID; sy++) {
                    for (int sx = 0; sx < GRID; sx++) {
                        vec3 p = readCache(sx, sy);
                        float dmin = 1e9;
                        for (int t = 0; t < MAX_K; t++) {
                            if (t >= s) break;
                            vec3 d = p - chosen[t];
                            dmin = min(dmin, dot(d, d));
                        }
                        if (dmin > bestD) { bestD = dmin; bestP = p; }
                    }
                }
                chosen[s] = bestP;
            }
            fragColor0 = vec4(chosen[frag.x], 1.0);
        } else {
            fragColor0 = texelFetch(u_image0, frag, 0);
        }
        fragColor1 = vec4(0.0, 0.0, 0.0, 1.0);
        return;
    }

    // PASSES 2..N-2: one k-means iteration over the cached samples.
    if (u_pass < NUM_PASSES - 1) {
        if (frag.y == 0 && frag.x < k) {
            int c = frag.x;
            vec3 sum = vec3(0.0);
            float cnt = 0.0;
            for (int sy = 0; sy < GRID; sy++) {
                for (int sx = 0; sx < GRID; sx++) {
                    vec3 p = readCache(sx, sy);
                    if (nearestCentroid(p, k) == c) { sum += p; cnt += 1.0; }
                }
            }
            fragColor0 = vec4(cnt > 0.0 ? sum / cnt : readCentroid(c), 1.0);
        } else {
            fragColor0 = texelFetch(u_image0, frag, 0);
        }
        fragColor1 = vec4(0.0, 0.0, 0.0, 1.0);
        return;
    }

    // FINAL PASS: map every source pixel to its nearest centroid, and
    // emit the palette as K vertical stripes on IMAGE1.
    vec3 src = texture(u_image1, v_texCoord).rgb;
    fragColor0 = vec4(readCentroid(nearestCentroid(src, k)), 1.0);
    int band = clamp(int(v_texCoord.x * float(k)), 0, k - 1);
    fragColor1 = vec4(readCentroid(band), 1.0);
}

#version 300 es
// Pixel Snapper (native GLSL) — stage 2/3: grid detection.
//
// Node setup: core GLSLShader, size_mode = custom, width 2048, height 8.
//   image0 = quantized image from stage 1 (becomes ping-pong after pass 0)
//   image1 = the SAME quantized image again (stable copy)
//   u_int0 = pixel_size override (0 = auto-detect)
// Output:
//   IMAGE0 = params texture; every pixel holds
//            (step_x, phase_x, step_y, phase_y) / 2048 as float RGBA.
//
// Method — a GLSL port of the Python estimator (jitter-robust, unlike
// autocorrelation which locks onto harmonics):
//   gradient profiles per axis -> strong local peaks (plateau-tolerant,
//   min 4px apart) -> median peak spacing = art-pixel size ->
//   phase = offset whose grid lines collect the most gradient energy.
// The whole estimator runs sequentially in one fragment of pass 1.
//
// Ping-pong layout: row 0 = column profile, row 1 = row profile,
// row 4 px 0 = resolved params. Supports sources up to 2048 px per side.
#pragma passes 3

precision highp float;

const int MAXDIM = 2048;
const int MAX_DIFFS = 700;
const float PEAK_THRESHOLD = 0.2;  // fraction of profile max
const int PEAK_MIN_DIST = 4;       // matches peak_distance_filter
const float MAX_STEP_RATIO = 1.8;

uniform sampler2D u_image0; // pass 0: quantized source; pass 1+: ping-pong
uniform sampler2D u_image1; // quantized source (stable)
uniform vec2 u_resolution;
uniform int u_int0;         // pixel_size override, 0 = auto
uniform int u_pass;

in vec2 v_texCoord;
layout(location = 0) out vec4 fragColor0;

float grayAt(ivec2 p) {
    vec3 c = texelFetch(u_image1, p, 0).rgb;
    return dot(c, vec3(0.299, 0.587, 0.114));
}

float prof(int x, int axis) { return texelFetch(u_image0, ivec2(x, axis), 0).r; }

bool isPeak(int i, int axis, float threshold) {
    float v = prof(i, axis);
    return v > threshold && v >= prof(i - 1, axis) && v > prof(i + 1, axis);
}

// Number of kept-peak spacings <= v (v < 0: count all spacings).
// Kept peaks follow the Python rule: first strong peak always kept, later
// ones only when > PEAK_MIN_DIST-1 past the last kept one.
int countSpacings(int axis, int n, float threshold, int v) {
    int count = 0;
    int last = -1;
    for (int i = 1; i < MAXDIM; i++) {
        if (i >= n - 1) break;
        if (isPeak(i, axis, threshold)) {
            if (last < 0) {
                last = i;
            } else if (i - last > PEAK_MIN_DIST - 1) {
                if (v < 0 || i - last <= v) count++;
                last = i;
            }
        }
    }
    return count;
}

// Median peak spacing of one axis profile; 0.0 if no reliable estimate.
// Arrayless on purpose: large local arrays miscompiled in fragment shaders.
float estimateStep(int axis, int n) {
    float maxVal = 0.0;
    for (int i = 0; i < MAXDIM; i++) {
        if (i >= n) break;
        maxVal = max(maxVal, prof(i, axis));
    }
    if (maxVal <= 0.0) return 0.0;
    float threshold = maxVal * PEAK_THRESHOLD;

    int m = countSpacings(axis, n, threshold, -1);
    if (m < 1) return 0.0;

    // upper median = (m/2 + 1)-th smallest spacing = smallest value v with
    // count(spacings <= v) >= m/2 + 1  (spacings are integers)
    int target = m / 2 + 1;
    for (int v = PEAK_MIN_DIST; v <= MAX_DIFFS; v++) {
        if (countSpacings(axis, n, threshold, v) >= target) return float(v);
    }
    return 0.0;
}

// Offset in [0, step) whose grid lines collect the most gradient energy.
float bestPhase(float st, int axis, int n) {
    int sti = max(int(st + 0.5), 1);
    float bestScore = -1.0;
    int bestOff = 0;
    for (int off = 0; off < 512; off++) {
        if (off >= sti) break;
        float s = 0.0;
        for (int j = 0; j < MAXDIM; j++) {
            int pos = int(float(off) + float(j) * st + 0.5);
            if (pos >= n) break;
            s += prof(pos, axis);
        }
        if (s > bestScore) { bestScore = s; bestOff = off; }
    }
    return float(bestOff);
}

void main() {
    ivec2 frag = ivec2(gl_FragCoord.xy);
    ivec2 sz = textureSize(u_image1, 0);
    int W = sz.x;
    int H = sz.y;

    // PASS 0: summed absolute central-difference gradients.
    if (u_pass == 0) {
        float v = 0.0;
        if (frag.y == 0 && frag.x >= 1 && frag.x < min(W - 1, MAXDIM)) {
            for (int y = 0; y < MAXDIM; y++) {
                if (y >= H) break;
                v += abs(grayAt(ivec2(frag.x + 1, y)) - grayAt(ivec2(frag.x - 1, y)));
            }
        } else if (frag.y == 1 && frag.x >= 1 && frag.x < min(H - 1, MAXDIM)) {
            for (int x = 0; x < MAXDIM; x++) {
                if (x >= W) break;
                v += abs(grayAt(ivec2(x, frag.x + 1)) - grayAt(ivec2(x, frag.x - 1)));
            }
        }
        fragColor0 = vec4(v, 0.0, 0.0, 1.0);
        return;
    }

    // PASS 1: full estimator in one fragment -> row 4 pixel 0.
    if (u_pass == 1) {
        if (frag.y == 4 && frag.x == 0) {
            float sx = estimateStep(0, W);
            float sy = estimateStep(1, H);

            if (u_int0 > 0) {
                sx = float(u_int0); sy = float(u_int0);
            } else if (sx <= 0.0 && sy <= 0.0) {
                sx = max(float(min(W, H)) / 64.0, 1.0); sy = sx;
            } else if (sx <= 0.0) { sx = sy; }
            else if (sy <= 0.0) { sy = sx; }
            else {
                float ratio = max(sx / sy, sy / sx);
                if (ratio > MAX_STEP_RATIO) { sx = min(sx, sy); sy = sx; }
                else { sx = (sx + sy) * 0.5; sy = sx; }
            }

            float phX = bestPhase(sx, 0, W);
            float phY = bestPhase(sy, 1, H);
            fragColor0 = vec4(sx / 2048.0, phX / 2048.0, sy / 2048.0, phY / 2048.0);
        } else {
            fragColor0 = texelFetch(u_image0, frag, 0);
        }
        return;
    }

    // FINAL PASS: plain copy — profiles stay in rows 0/1, params in row 4.
    // Consumers texelFetch absolute rows (upload/readback flips are
    // symmetric, so GL row addressing survives node hops).
    fragColor0 = texelFetch(u_image0, frag, 0);
}

#version 300 es
// Pixel Snapper (native GLSL) — stage 3/3: snap to grid (majority vote).
//
// Node setup: core GLSLShader, size_mode = from_input.
//   image0 = quantized image from stage 1 (becomes ping-pong after pass 0)
//   image1 = params texture from stage 2
//   image2 = palette stripes from stage 1 (IMAGE1 output)
//   u_int0 = color_count K (same value as stage 1)
// Output:
//   IMAGE0 = snapped image at full resolution: every grid cell painted
//            with its majority color (majority vote preserves dithering).
//
// Pass 0 computes each cell's winning palette color into the top-left
// corner of the buffer (one pixel per cell); pass 1 paints every output
// pixel by looking up its cell. For a true native-resolution asset,
// downscale this output by 1/pixel_size with nearest-neighbor.
#pragma passes 2

precision highp float;

const int MAX_K = 32;
const int MAX_CELL = 128; // max art-pixel size in source px

uniform sampler2D u_image0; // pass 0: quantized source; pass 1: cell map
uniform sampler2D u_image1; // params texture (step/phase, /2048)
uniform sampler2D u_image2; // palette stripes
uniform vec2 u_resolution;
uniform int u_int0;         // color_count K
uniform int u_pass;

in vec2 v_texCoord;
layout(location = 0) out vec4 fragColor0;

int kColors() { return clamp(u_int0 <= 0 ? 16 : u_int0, 2, MAX_K); }

vec3 paletteColor(int i, int k) {
    return texture(u_image2, vec2((float(i) + 0.5) / float(k), 0.5)).rgb;
}

int nearestPalette(vec3 p, int k) {
    float best = 1e9;
    int bi = 0;
    for (int j = 0; j < MAX_K; j++) {
        if (j >= k) break;
        vec3 d = p - paletteColor(j, k);
        float dist = dot(d, d);
        if (dist < best) { best = dist; bi = j; }
    }
    return bi;
}

void main() {
    ivec2 frag = ivec2(gl_FragCoord.xy);
    int k = kColors();
    vec4 params = texelFetch(u_image1, ivec2(0, 4), 0) * 2048.0;
    float stepX = max(params.x, 1.0);
    float phX = params.y;
    float stepY = max(params.z, 1.0);
    float phY = params.w;
    int W = int(u_resolution.x);
    int H = int(u_resolution.y);

    // Pixel x belongs to cell floor((x - phase) / step); cell ids are
    // shifted so the first in-image cell is 0.
    int cx0 = int(floor((0.0 - phX) / stepX));
    int cy0 = int(floor((0.0 - phY) / stepY));

    if (u_pass == 0) {
        // Fragment (cx, cy) = majority palette color of that cell.
        int cellX = frag.x + cx0;
        int cellY = frag.y + cy0;
        float xs = phX + float(cellX) * stepX;
        float xe = xs + stepX;
        float ys = phY + float(cellY) * stepY;
        float ye = ys + stepY;
        int x0 = max(int(ceil(xs - 0.0001)), 0);
        int x1 = min(int(ceil(xe - 0.0001)), W);
        int y0 = max(int(ceil(ys - 0.0001)), 0);
        int y1 = min(int(ceil(ye - 0.0001)), H);

        if (x0 >= x1 || y0 >= y1 || x0 >= W || y0 >= H) {
            fragColor0 = vec4(0.0, 0.0, 0.0, 1.0);
            return;
        }

        int counts[MAX_K];
        for (int j = 0; j < MAX_K; j++) counts[j] = 0;

        for (int dy = 0; dy < MAX_CELL; dy++) {
            int y = y0 + dy;
            if (y >= y1) break;
            for (int dx = 0; dx < MAX_CELL; dx++) {
                int x = x0 + dx;
                if (x >= x1) break;
                vec3 p = texelFetch(u_image0, ivec2(x, y), 0).rgb;
                counts[nearestPalette(p, k)]++;
            }
        }

        int bestCount = -1;
        int bestId = 0;
        for (int j = 0; j < MAX_K; j++) {
            if (j >= k) break;
            if (counts[j] > bestCount) { bestCount = counts[j]; bestId = j; }
        }
        fragColor0 = vec4(paletteColor(bestId, k), 1.0);
        return;
    }

    // PASS 1: paint every pixel with its cell's winning color.
    int cellX = int(floor((float(frag.x) - phX) / stepX)) - cx0;
    int cellY = int(floor((float(frag.y) - phY) / stepY)) - cy0;
    fragColor0 = vec4(texelFetch(u_image0, ivec2(cellX, cellY), 0).rgb, 1.0);
}
